import { useState, useEffect } from 'react';
import { getStatsContratantes, getStatsLocais } from '../services/api';

function moeda(v) {
  return new Intl.NumberFormat('pt-BR',{style:'currency',currency:'BRL'}).format(v||0);
}

function TabelaCRM({ dados, loading, colunaChave }) {
  if (loading) return <div className="loading">Carregando...</div>;
  if (!dados.length) return <div className="empty">Nenhum dado encontrado.</div>;

  const max = Math.max(...dados.map(d => d.totalFaturamento), 1);

  return (
    <div className="crm-lista">
      {dados.map((item, i) => (
        <div key={i} className="crm-item">
          <div className="crm-rank">#{i+1}</div>
          <div className="crm-info">
            <div className="crm-nome">{item.nome}</div>
            <div className="crm-bar-track">
              <div className="crm-bar-fill"
                style={{width:`${(item.totalFaturamento/max)*100}%`}}/>
            </div>
            <div className="crm-meta">
              <span>🎵 {item.totalShows} show{item.totalShows!==1?'s':''}</span>
              <span>💰 Média: {moeda(item.mediaCache)}</span>
              <span>📅 Último: {item.ultimoShow}</span>
            </div>
          </div>
          <div className="crm-total">{moeda(item.totalFaturamento)}</div>
        </div>
      ))}
    </div>
  );
}

export default function CRMPage({ shows }) {
  const [aba, setAba]                   = useState('contratantes');
  const [contratantes, setContratantes] = useState([]);
  const [locais, setLocais]             = useState([]);
  const [loading, setLoading]           = useState(false);
  const [busca, setBusca]               = useState('');

  useEffect(() => {
    async function carregar() {
      setLoading(true);
      try {
        const [c, l] = await Promise.all([getStatsContratantes(), getStatsLocais()]);
        setContratantes(c);
        setLocais(l);
      } catch (err) { console.error(err); }
      finally { setLoading(false); }
    }
    carregar();
  }, [shows]);

  const dadosFiltrados = (aba === 'contratantes' ? contratantes : locais)
    .filter(d => !busca || d.nome.toLowerCase().includes(busca.toLowerCase()));

  // KPIs
  const totalContratantes = new Set(shows.map(s=>s.contratante).filter(Boolean)).size;
  const totalLocais       = new Set(shows.map(s=>s.endereco).filter(Boolean)).size;
  const topContratante    = contratantes[0];
  const topLocal          = locais[0];

  return (
    <div className="crm-page">
      <div className="page-header">
        <div>
          <h1 className="page-title">👥 CRM</h1>
          <p className="page-subtitle">Histórico de contratantes e locais</p>
        </div>
      </div>

      {/* KPIs */}
      <div className="crm-kpis">
        <div className="crm-kpi-card">
          <div className="crm-kpi-icon">🤝</div>
          <div>
            <div className="crm-kpi-val">{totalContratantes}</div>
            <div className="crm-kpi-label">Contratantes únicos</div>
          </div>
        </div>
        <div className="crm-kpi-card">
          <div className="crm-kpi-icon">📍</div>
          <div>
            <div className="crm-kpi-val">{totalLocais}</div>
            <div className="crm-kpi-label">Locais únicos</div>
          </div>
        </div>
        {topContratante && (
          <div className="crm-kpi-card">
            <div className="crm-kpi-icon">🏆</div>
            <div>
              <div className="crm-kpi-val" style={{fontSize:14}}>{topContratante.nome}</div>
              <div className="crm-kpi-label">Maior contratante ({topContratante.totalShows} shows)</div>
            </div>
          </div>
        )}
        {topLocal && (
          <div className="crm-kpi-card">
            <div className="crm-kpi-icon">⭐</div>
            <div>
              <div className="crm-kpi-val" style={{fontSize:14}}>{topLocal.nome}</div>
              <div className="crm-kpi-label">Local mais frequente ({topLocal.totalShows}x)</div>
            </div>
          </div>
        )}
      </div>

      {/* Abas e busca */}
      <div className="crm-toolbar">
        <div className="crm-abas">
          <button className={'crm-aba'+(aba==='contratantes'?' ativa':'')}
            onClick={()=>{setAba('contratantes');setBusca('');}}>
            🤝 Contratantes ({contratantes.length})
          </button>
          <button className={'crm-aba'+(aba==='locais'?' ativa':'')}
            onClick={()=>{setAba('locais');setBusca('');}}>
            📍 Locais ({locais.length})
          </button>
        </div>
        <input className="input busca-input" style={{maxWidth:280}}
          placeholder={`Buscar ${aba}...`}
          value={busca} onChange={e=>setBusca(e.target.value)}/>
      </div>

      <TabelaCRM dados={dadosFiltrados} loading={loading} colunaChave={aba}/>
    </div>
  );
}
